### Swift Overriding

Overriding allows a subclass to provide its own implementation of a method, property, or subscript that is inherited from a superclass. The `override` keyword is required.

**Overriding Methods:**

```swift
class Vehicle {
    func startEngine() -> String {
        return "Engine starting..."
    }
}

class ElectricCar: Vehicle {
    override func startEngine() -> String {
        return "Electric motor powering up silently..."
    }
}

class HybridCar: Vehicle {
    override func startEngine() -> String {
        // Call superclass implementation
        let baseMessage = super.startEngine()
        return baseMessage + " (electric mode available)"
    }
}

print(ElectricCar().startEngine())
print(HybridCar().startEngine())
```

**Overriding Properties:**

```swift
class Vehicle {
    var maxSpeed: Double {
        return 200.0
    }

    var numberOfWheels: Int {
        return 4
    }
}

class Motorcycle: Vehicle {
    override var numberOfWheels: Int {
        return 2
    }

    override var maxSpeed: Double {
        return 280.0
    }
}

class Truck: Vehicle {
    override var maxSpeed: Double {
        return 120.0
    }
}
```

**Overriding Rules:**

| Element | Overrideable? | Notes |
|---------|--------------|-------|
| Instance methods | Yes | Must use `override` |
| Computed properties | Yes | Read-only or read-write |
| Stored properties | No | Cannot override stored |
| Property observers | Yes | Can add to inherited properties |
| Type methods | Yes | If marked `class` not `static` |

**Preventing Overrides:**

```swift
class Parent {
    // Cannot be overridden
    final func fixedBehavior() { }

    // Can be overridden
    class func overridable() { }

    // Cannot be overridden (static = final class)
    static func notOverridable() { }
}
```

> **Key Point:** You must use the `override` keyword for any method or property that overrides a superclass member. The compiler will error if `override` is used without an existing superclass declaration, or if it is missing when overriding.

`super` can be used to access the superclass implementation of a method, property, or subscript.

codeExample:
import Foundation

class Shape {
    var name: String { "Shape" }

    func area() -> Double {
        return 0
    }

    func description() -> String {
        return "\(name) with area \(area())"
    }
}

class Circle: Shape {
    var radius: Double

    init(radius: Double) {
        self.radius = radius
    }

    override var name: String { "Circle" }

    override func area() -> Double {
        return Double.pi * radius * radius
    }
}

class Rectangle: Shape {
    var width: Double
    var height: Double

    init(width: Double, height: Double) {
        self.width = width
        self.height = height
    }

    override var name: String { "Rectangle" }

    override func area() -> Double {
        return width * height
    }
}

let shapes: [Shape] = [Circle(radius: 5), Rectangle(width: 4, height: 6)]
for shape in shapes {
    print(shape.description())
}
